@page "/account/login"
@using Microsoft.AspNetCore.Identity
@using System.ComponentModel.DataAnnotations
@inject SignInManager<IdentityUser> SignInManager
@inject NavigationManager Navigation

<PageTitle>Login</PageTitle>

<div class="row justify-content-center mt-5">
    <div class="col-md-4">
        <h3 class="text-center mb-4">Sign In</h3>

        @if (!string.IsNullOrEmpty(errorMessage))
        {
            <div class="alert alert-danger">@errorMessage</div>
        }

        <EditForm Model="Input" method="post" OnValidSubmit="LoginUser" FormName="login" Enhance>
            <DataAnnotationsValidator />

            <div class="mb-3">
                <label for="email" class="form-label">Email</label>
                <InputText id="email" @bind-Value="Input.Email" class="form-control" placeholder="name@example.com" />
                <ValidationMessage For="() => Input.Email" />
            </div>

            <div class="mb-3">
                <label for="password" class="form-label">Password</label>
                <InputText id="password" @bind-Value="Input.Password" class="form-control" type="password" />
                <ValidationMessage For="() => Input.Password" />
            </div>

            <button type="submit" class="btn btn-primary w-100">Sign In</button>
        </EditForm>
    </div>
</div>

@code {
    private string? errorMessage;

    [SupplyParameterFromForm]
    private LoginModel Input { get; set; } = new();

    [SupplyParameterFromQuery]
    private string? ReturnUrl { get; set; }

    private async Task LoginUser()
    {
        var result = await SignInManager.PasswordSignInAsync(
            Input.Email, Input.Password, isPersistent: false, lockoutOnFailure: false);

        if (result.Succeeded)
        {
            Navigation.NavigateTo(ReturnUrl ?? "/", forceLoad: true);
        }
        else
        {
            errorMessage = "Invalid email or password.";
        }
    }

    private sealed class LoginModel
    {
        [Required]
        [EmailAddress]
        public string Email { get; set; } = "";

        [Required]
        [DataType(DataType.Password)]
        public string Password { get; set; } = "";
    }
}

@page "/account/logout"
@using Microsoft.AspNetCore.Identity
@inject SignInManager<IdentityUser> SignInManager
@inject NavigationManager Navigation

<PageTitle>Logging out...</PageTitle>

@code {
    protected override async Task OnInitializedAsync()
    {
        await SignInManager.SignOutAsync();
        Navigation.NavigateTo("/", forceLoad: true);
    }
}

@page "/admin/users"
@rendermode InteractiveServer
@using Microsoft.AspNetCore.Authorization
@using Microsoft.AspNetCore.Identity
@attribute [Authorize(Roles = "Admin")]
@inject UserManager<IdentityUser> UserManager

<PageTitle>User Management</PageTitle>

<h1>User Management</h1>
<p class="text-muted">Manage all registered users and their roles.</p>

@if (users is null)
{
    <p><em>Loading users...</em></p>
}
else
{
    <table class="table table-striped">
        <thead>
            <tr>
                <th>Email</th>
                <th>Username</th>
                <th>Roles</th>
                <th>Email Confirmed</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var (user, roles) in users)
            {
                <tr>
                    <td>@user.Email</td>
                    <td>@user.UserName</td>
                    <td>
                        @foreach (var role in roles)
                        {
                            <span class="badge bg-primary me-1">@role</span>
                        }
                    </td>
                    <td>
                        @if (user.EmailConfirmed)
                        {
                            <span class="badge bg-success">Yes</span>
                        }
                        else
                        {
                            <span class="badge bg-warning">No</span>
                        }
                    </td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<(IdentityUser user, IList<string> roles)>? users;

    protected override async Task OnInitializedAsync()
    {
        var allUsers = UserManager.Users.ToList();
        var result = new List<(IdentityUser, IList<string>)>();

        foreach (var user in allUsers)
        {
            var roles = await UserManager.GetRolesAsync(user);
            result.Add((user, roles));
        }

        users = result;
    }
}

